class Solution:
    def closestCost(self, baseCosts, toppingCosts, target):
        best = [None]
        def consider(cost):
            if best[0] is None:
                best[0] = cost
                return
            cur = best[0]
            if abs(cost - target) < abs(cur - target) or (abs(cost - target) == abs(cur - target) and cost < cur):
                best[0] = cost
        def dfs(i, cost):
            if i == len(toppingCosts):
                consider(cost)
                return
            for k in range(3):
                dfs(i + 1, cost + k * toppingCosts[i])
        for b in baseCosts:
            dfs(0, b)
        return best[0]

