class Solution:
    def closestCost(self, baseCosts, toppingCosts, target):
        best = float('inf')
        bestcost = None
        sums = {0}
        for t in toppingCosts:
            ns = set()
            for s in sums:
                ns.add(s)
                ns.add(s + t)
                ns.add(s + 2 * t)
            sums = ns
        for b in baseCosts:
            for s in sums:
                cost = b + s
                d = abs(cost - target)
                if d < best or (d == best and cost < bestcost):
                    best = d
                    bestcost = cost
        return bestcost

