var closestCost = function(baseCosts, toppingCosts, target) {
    let sums = new Set([0]);
    for (const t of toppingCosts) {
        const ns = new Set();
        for (const s of sums) {
            ns.add(s);
            ns.add(s + t);
            ns.add(s + 2 * t);
        }
        sums = ns;
    }
    let best = Infinity, bestcost = null;
    for (const b of baseCosts) {
        for (const s of sums) {
            const cost = b + s;
            const d = Math.abs(cost - target);
            if (d < best || (d === best && cost < bestcost)) {
                best = d;
                bestcost = cost;
            }
        }
    }
    return bestcost;
};
